function run(){window.dispatchEvent(new CustomEvent('jc-canvas-run-node',{detail:p.id}))}</script>
<template><div class="x" :class="{sel:selected}" :style="{borderColor:selected?'#fb923c':'var(--border)'}"><Handle type="target" :position="Position.Left" :style="{background:'#fb923c',width:10,height:10,border:'none'}"/><div class="xh"><div class="xi" style="background:rgba(251,146,60,.18);color:#fdba74"><span class="mso" style="font-size:13px">film_frames</span></div><div class="xl">首尾帧</div><button class="xr" :disabled="data.status==='running'" @pointerdown.stop @click.stop="run"><span class="mso">play_arrow</span></button></div><div class="xb" @mousedown.stop><div class="fr"><div style="flex:1;text-align:center"><div style="font-size:10px;color:var(--ink3)">首帧</div><img v-if="data.firstFrameUrl" :src="data.firstFrameUrl" class="fi"/></div><div style="flex:1;text-align:center"><div style="font-size:10px;color:var(--ink3)">尾帧</div><img v-if="data.lastFrameUrl" :src="data.lastFrameUrl" class="fi"/></div></div><div v-if="!data.firstFrameUrl&&!data.lastFrameUrl" style="font-size:10px;color:var(--ink3);text-align:center">连接上游视频后运行</div><div v-if="data.error" class="xe"><span class="mso" style="font-size:11px">error</span>{{data.error}}</div></div><Handle type="source" :position="Position.Right" id="first" :style="{background:'#fb923c',width:10,height:10,border:'none',top:'36%'}"/><Handle type="source" :position="Position.Right" id="last" :style="{background:'#fb923c',width:10,height:10,border:'none',top:'64%'}"/></div></template>
